{
"title": "गेटर बनाम प्रत्यक्ष प्रॉपर्टी एक्सेस",
  "group": "उन्नत इंटरफ़ेस",
  "options": [
    {
      "text": "लूप का उपयोग करें"
    },
    {
      "text": "मान तक पहुँचने के लिए मेथड को कॉल करें"
    },
    {
      "text": "मान को सीधे एक्सेस करें"
    },
    {
      "text": "त्रुटि फेंके"
    }
  ],
  "questionProse": [
    "आपको एक जावास्क्रिप्ट ऑब्जेक्ट प्रॉपर्टी जिसे गेटर मेथड का उपयोग करता है, कैसे एक्सेस करना चाहिए?"
  ],
  "explanationProse": [
    "जावास्क्रिप्ट में, गेटर को सामान्य प्रॉपर्टी की तरह एक्सेस किया जा सकता है। इसे फ़ंक्शन की तरह कॉल करने की ज़रूरत नहीं है।\n    इस उदाहरण में, `obj.val` को सीधे एक्सेस करने से गेटर मेथड कॉल हो जाता है और `got it!` आउटपुट मिलता है।"
  ]
}
